SELECT ?athlete ?birthDate ?eventDate ?age WHERE {
  wd:Q8038036 wdt:P585 ?eventDate .
  wd:Q8038036 wdt:P585 ?eventDate .

  ?athlete p:P166 ?award .
  ?award ps:P166 wd:Q80341 ;
         pq:P1971 wd:Q8038036 ;
         pq:P4100 wd:Q19235 .
  ?athlete wdt:P27 wd:Q668 ;
            wdt:P569 ?birthDate .

  BIND(YEAR(?eventDate) - YEAR(?birthDate) AS ?ageCalc)
  BIND(MONTH(?eventDate) - MONTH(?birthDate) AS ?monthDiff)
  BIND(DAY(?eventDate) - DAY(?birthDate) AS ?dayDiff)

  BIND(IF(?monthDiff > 0 || (?monthDiff = 0 && ?dayDiff >= 0), ?ageCalc, ?ageCalc - 1) AS ?age)
}

SELECT ?birthDate ?eventDate (YEAR(?eventDate) - YEAR(?birthDate) AS ?age) WHERE {
  wd:Q8038036 wdt:P585 ?eventDate .
  wd:Q1824834 wdt:P569 ?birthDate .
  wd:Q1824834 wdt:P166/wdt:P361 wd:Q8038036 .
}

SELECT ?athlete ?birthDate ?eventDate WHERE {
  wd:Q8038036 wdt:P1346 ?athlete .
  wd:Q8038036 wdt:P585 ?eventDate .
  ?athlete wdt:P569 ?birthDate .
}
